const budget = 92500;
const records = {
  R1: {m1:0.82,m2:0,m3:0,m4:2.45},
  R2: {m1:0.67,m2:0,m3:1,m4:4.21},
  R3: {m1:0.78,m2:1,m3:1,m4:8.49},
  R4: {m1:0.79,m2:1,m3:0,m4:5.03},
};
const sum = Object.values(records).reduce((a,r)=>a+(r.m1*r.m2 - 0.6*r.m3 + r.m4),0);
for (const [id,r] of Object.entries(records)) {
  const p = r.m1*r.m2 - 0.6*r.m3 + r.m4;
  const econ = budget * p / sum;
  const breach = (r.m1 < 0.7) || (r.m3 > 0);
  const needs = breach || (r.m2 === 1 && r.m3 === 0 && r.m1 >= 0.7);
  console.log(id, {p, econ, breach, needs});
}
