sed -n '1,120p' [EXCLUDED_GENERATED_ARTIFACT] && sed -n '1,240p' [EXCLUDED_GENERATED_ARTIFACT] && node - <<'NODE'
const fs = require('fs');
const csv = fs.readFileSync('[EXCLUDED_GENERATED_ARTIFACT]', 'utf8').trim().split(/\n/);
const header = csv[0].split(',');
const rows = csv.slice(1).map(line => {
  const vals = [];
  let cur = '', inQ = false;
  for (let i = 0; i < line.length; i++) {
    const ch = line[i];
    if (ch === '"') { inQ = !inQ; continue; }
    if (ch === ',' && !inQ) { vals.push(cur); cur = ''; continue; }
    cur += ch;
  }
  vals.push(cur);
  return Object.fromEntries(header.map((h, i) => [h, vals[i]]));
});
const expected = {
  R1: { p: 2.45, tech: 4, queue: 4, breach: '0', needs: '0' },
  R2: { p: 3.61, tech: 3, queue: 2, breach: '1', needs: '1' },
  R3: { p: 8.67, tech: 1, queue: 1, breach: '1', needs: '1' },
  R4: { p: 5.82, tech: 2, queue: 3, breach: '0', needs: '1' },
};
let ok = true;
for (const r of rows) {
  const e = expected[r.record_id];
  const p = Number(r.priority_value);
  if (!e || Math.abs(p - e.p) > 1e-6 || r.technical_impact_rank !== String(e.tech) || r.review_queue_rank !== String(e.queue) || r.hard_threshold_breach_flag !== e.breach || r.needs_review_flag !== e.needs) ok = false;
}
const econ = rows.reduce((a, r) => a + Number(r.economic_impact_usd), 0);
console.log(JSON.stringify({rowCount: rows.length, headerCount: header.length, valid: ok, econSum: econ.toFixed(2)}, null, 2));
NODE

